import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

function getIcon(type, status) {
  if (type === 'collection') {
    if (status === 'Booked') return { icon: 'calendar-event', bg: '#E1F5EE', color: '#085041' };
    if (status === 'Processing') return { icon: 'loader-2', bg: '#FAEEDA', color: '#633806' };
    return { icon: 'check', bg: '#EAF3DE', color: '#27500A' };
  }
  if (type === 'customer') return { icon: 'user-plus', bg: '#E6F1FB', color: '#0C447C' };
  if (type === 'asset') return { icon: 'box', bg: '#EEEDFE', color: '#3C3489' };
  return { icon: 'circle', bg: '#F1EFE8', color: '#444441' };
}

function getTitle(activity) {
  if (activity.activity_type === 'collection') {
    return `Collection ${activity.status?.toLowerCase() || 'updated'} — ${activity.record_id || 'Job'}`;
  }
  if (activity.activity_type === 'customer') {
    return `New customer created — ${activity.title_detail}`;
  }
 if (activity.activity_type === 'asset') {
  return `Asset ${activity.status?.toLowerCase() || 'updated'} — ${activity.title_detail || ('#' + activity.record_id)}`;

  }
  return activity.title_detail || 'Activity';
}

function timeAgo(dateStr) {
  if (!dateStr) return '';
  const date = new Date(dateStr);
  const now = new Date();
  const diffMs = now - date;
  const diffMins = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMins / 60);
  const diffDays = Math.floor(diffHours / 24);
  if (diffMins < 1) return 'just now';
  if (diffMins < 60) return `${diffMins}m ago`;
  if (diffHours < 24) return `${diffHours}h ago`;
  if (diffDays === 1) return 'yesterday';
  return `${diffDays}d ago`;
}

function App() {
  const [model, setModel] = React.useState(appsmith.model);

  React.useEffect(() => {
    appsmith.onModelChange((newModel) => {
      setModel({ ...newModel });
    });
  }, []);

  let activities = model.activities;
  if (typeof activities === 'string') {
    try {
      activities = JSON.parse(activities);
    } catch (e) {
      activities = [];
    }
  }
  activities = activities || [];

  if (activities.length === 0) {
    return (
      <div style={{ textAlign: 'center', padding: '24px 0', color: '#9ca3af', fontSize: '13px', fontFamily: 'sans-serif' }}>
        No recent activity
      </div>
    );
  }

  return (
    <div style={{ fontFamily: 'sans-serif', display: 'flex', flexDirection: 'column', gap: '8px' }}>
      {activities.map((activity, i) => {
        const { icon, bg, color } = getIcon(activity.activity_type, activity.status);
        return (
          <div key={i} style={{
            background: '#fff', border: '0.5px solid #e5e7eb', borderRadius: '8px',
            padding: '12px 14px', display: 'flex', alignItems: 'center', gap: '12px'
          }}>
            <div style={{
              width: '36px', height: '36px', borderRadius: '50%', background: bg,
              display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0
            }}>
              <i className={`ti ti-${icon}`} style={{ fontSize: '18px', color: color }}></i>
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: '13px', fontWeight: 500, color: '#111827' }}>{getTitle(activity)}</div>
              <div style={{ fontSize: '12px', color: '#6b7280' }}>{activity.created_by || 'System'}</div>
            </div>
            <div style={{ fontSize: '12px', color: '#9ca3af', flexShrink: 0 }}>{timeAgo(activity.created_at)}</div>
          </div>
        );
      })}
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
